from typing import List, Tuple, Optional


class ASTNode:
    def __init__(self, type, value=None, op=None, left=None, right=None, operand=None):
        self.type = type
        self.value = value
        self.op = op
        self.left = left
        self.right = right
        self.operand = operand


def tokenize(expression: str) -> List[Tuple[str, str]]:
    """Convert expression string to list of tokens."""
    tokens = []
    i = 0
    expression = expression.strip()

    while i < len(expression):
        # Skip whitespace
        if expression[i].isspace():
            i += 1
            continue

        # Numbers (including floats)
        if expression[i].isdigit() or (expression[i] == '.' and i + 1 < len(expression) and expression[i + 1].isdigit()):
            j = i
            has_dot = False
            while j < len(expression) and (expression[j].isdigit() or (expression[j] == '.' and not has_dot)):
                if expression[j] == '.':
                    has_dot = True
                j += 1
            tokens.append(('NUMBER', expression[i:j]))
            i = j
            continue

        # Operators and parentheses
        if expression[i] in '+-*/()':
            tokens.append((expression[i], expression[i]))
            i += 1
            continue

        raise ValueError(f"Invalid token at position {i}: {expression[i]}")

    return tokens


class Parser:
    def __init__(self, tokens: List[Tuple[str, str]]):
        self.tokens = tokens
        self.pos = 0

    def current_token(self) -> Optional[Tuple[str, str]]:
        if self.pos < len(self.tokens):
            return self.tokens[self.pos]
        return None

    def consume(self, expected_type: str = None) -> Tuple[str, str]:
        token = self.current_token()
        if token is None:
            raise ValueError("Unexpected end of expression")
        if expected_type and token[0] != expected_type:
            raise ValueError(f"Expected {expected_type}, got {token[0]}")
        self.pos += 1
        return token

    def parse(self) -> ASTNode:
        if not self.tokens:
            raise ValueError("Empty input")
        node = self.expression()
        if self.current_token() is not None:
            raise ValueError(f"Unexpected token: {self.current_token()}")
        return node

    def expression(self) -> ASTNode:
        """Parse addition and subtraction (lowest precedence)."""
        left = self.term()

        while self.current_token() and self.current_token()[0] in ('+', '-'):
            op = self.consume()[1]
            right = self.term()
            left = ASTNode(type='binop', op=op, left=left, right=right)

        return left

    def term(self) -> ASTNode:
        """Parse multiplication and division (higher precedence)."""
        left = self.factor()

        while self.current_token() and self.current_token()[0] in ('*', '/'):
            op = self.consume()[1]
            right = self.factor()
            left = ASTNode(type='binop', op=op, left=left, right=right)

        return left

    def factor(self) -> ASTNode:
        """Parse numbers and parenthesized expressions."""
        token = self.current_token()

        if token is None:
            raise ValueError("Unexpected end of expression")

        if token[0] == 'NUMBER':
            self.consume()
            return ASTNode(type='number', value=float(token[1]))

        if token[0] == '(':
            self.consume()
            node = self.expression()
            if self.current_token() is None or self.current_token()[0] != ')':
                raise ValueError("Unmatched opening parenthesis")
            self.consume()
            return node

        raise ValueError(f"Unexpected token: {token[0]}")


def parse(expression: str) -> ASTNode:
    tokens = tokenize(expression)
    parser = Parser(tokens)
    return parser.parse()


def evaluate(node: ASTNode) -> float:
    if node.type == 'number':
        return node.value

    if node.type == 'binop':
        left = evaluate(node.left)
        right = evaluate(node.right)

        if node.op == '+':
            return left + right
        elif node.op == '-':
            return left - right
        elif node.op == '*':
            return left * right
        elif node.op == '/':
            return left / right

    raise ValueError(f"Unknown node type: {node.type}")
